from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    try:
        searcher = LeannSearcher(index_path)
        passage_manager = searcher.passage_manager

        total_passages = len(passage_manager)

        # Collect all metadata fields and their values
        all_metadata = []
        for passage_id in passage_manager:
            passage_data = passage_manager[passage_id]
            metadata = passage_data.get("metadata", {})
            all_metadata.append(metadata)

        # Extract unique field names
        metadata_fields = set()
        for metadata in all_metadata:
            metadata_fields.update(metadata.keys())

        # Count field values
        field_value_counts = defaultdict(Counter)
        for metadata in all_metadata:
            for field_name, field_value in metadata.items():
                field_value_counts[field_name][field_value] += 1

        # Convert to regular dict for JSON serialization
        field_value_counts = {
            field_name: dict(value_counter) 
            for field_name, value_counter in field_value_counts.items()
        }

        return {
            "total_passages": total_passages,
            "metadata_fields": sorted(list(metadata_fields)),
            "field_value_counts": field_value_counts
        }

    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found at {index_path}") from e

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    try:
        searcher = LeannSearcher(index_path)
        passage_manager = searcher.passage_manager

        total_passages = len(passage_manager)

        # Check which passages have all required fields
        passages_with_all_fields = 0
        field_presence = defaultdict(int)
        missing_fields_in_passages = set(required_fields)

        for passage_id in passage_manager:
            passage_data = passage_manager[passage_id]
            metadata = passage_data.get("metadata", {})

            # Check if all required fields are present
            has_all_fields = True
            for field in required_fields:
                if field not in metadata:
                    has_all_fields = False
                    missing_fields_in_passages.discard(field)  # Remove fields found in some passages
                    break

            if has_all_fields:
                passages_with_all_fields += 1

            # Track presence of each individual field
            for field in required_fields:
                if field in metadata:
                    field_presence[field] += 1

        # Calculate percentages
        coverage_percentage = (passages_with_all_fields / total_passages * 100) if total_passages > 0 else 0
        field_coverage = {
            field: (count / total_passages * 100) if total_passages > 0 else 0
            for field, count in field_presence.items()
        }

        return {
            "coverage_percentage": round(coverage_percentage, 2),
            "field_coverage": {field: round(perc, 2) for field, perc in field_coverage.items()},
            "missing_fields": sorted(list(missing_fields_in_passages))
        }

    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found at {index_path}") from e
